        // ==========================================
        // ⭐ 静态变量回退机制
        const targetRegion = "北部非洲地区部";
        const targetOffice = "埃及代表处";
        const targetDate = "2026-01-01";
        // ==========================================

        const cStr=localStorage.getItem('globalConfig'); let csrfToken="";
        if(cStr){const m=cStr.match(/([A-Fa-f0-9]{64})/); if(m)csrfToken=m[0]; else try{let o=JSON.parse(cStr);csrfToken=o.csrfToken||(o.configData&&o.configData.csrfToken)||""}catch(e){} }
        const fetchHeaders = { "accept": "application/json, text/plain, */*", "content-type": "application/json;charset=UTF-8", "x-gde-csrf-token": csrfToken, "x-requested-with": "XMLHttpRequest" };

        // 🧠 核心取值引擎：绝对优先级 (Formula > Summing > Average)
        function getSmartValue(cell) {
            if (cell === null || cell === undefined) return "";
            if (typeof cell !== 'object') return cell; 

            if (cell.formula !== undefined && cell.formula !== null && cell.formula !== "") return cell.formula;
            if (cell.summing !== undefined && cell.summing !== null && cell.summing !== "") return cell.summing;
            if (cell.average !== undefined && cell.average !== null && cell.average !== "") return cell.average;

            return JSON.stringify(cell);
        }

        // ⭐ 智能汇总提取引擎 (兼容透视表 totalsData 与普通表 sumData)
        function extractSmartSumData(resObj) {
            if (!resObj) return null;
            if (resObj.totalsData && resObj.totalsData.columns) return resObj.totalsData.columns;
            if (resObj.data && !Array.isArray(resObj.data) && resObj.data.totalsData && resObj.data.totalsData.columns) return resObj.data.totalsData.columns;
            if (resObj.data && Array.isArray(resObj.data) && resObj.data[0] && resObj.data[0].totalsData && resObj.data[0].totalsData.columns) return resObj.data[0].totalsData.columns;

            if (resObj.sumData) return resObj.sumData;
            if (resObj.data && !Array.isArray(resObj.data) && resObj.data.sumData) return resObj.data.sumData;
            if (resObj.data && Array.isArray(resObj.data) && resObj.data[0] && resObj.data[0].sumData) return resObj.data[0].sumData;
            return null;
        }

        function extractRows(obj) {
            if (obj && obj.data && Array.isArray(obj.data) && obj.data[0] && Array.isArray(obj.data[0].data)) return obj.data[0].data;
            let arr = obj.results || (obj.data && obj.data.results) || obj.data || [];
            return Array.isArray(arr) ? arr : (Array.isArray(obj) ? obj : [arr]);
        }

        // 📝 基础明细 Payload 骨架
        const baseDetailPayload = {
          "region_code": [
                    "026902"
          ],
          "office_code": [
                    "026921"
          ],
          "bg": [
                    "CNBG"
          ],
          "t1_operator": [],
          "na_type": [],
          "customer_number": [],
          "branch_code": [],
          "subnet_code": [],
          "risk_status": [],
          "duetime_year": [],
          "product_line": [],
          "category_name": [],
          "country_code": [
                    "EG"
          ],
          "network": [],
          "version": "2026",
          "reduction_scenario": [
                    "2"
          ],
          "is_evolution": [],
          "group_by": "t1_operator_code",
          "need_summary": true
};

        // 🚀 动态时间轴配置 
        const sysDate = new Date();
        const currentYear = sysDate.getFullYear();
        const currentMonth = sysDate.getMonth() + 1;

        const prevDateObj = new Date(sysDate.getFullYear(), sysDate.getMonth() - 1, 1);
        const prevYear = prevDateObj.getFullYear();
        const prevMonth = prevDateObj.getMonth() + 1;

        const padZ = (n) => n.toString().padStart(2, '0');

        let runConfigs = [ { month: null, year: null, label: "默认" } ];



        let finalSummary = [];

        // ==========================================
        // 🔄 阶段一：自动执行引擎
        // ==========================================
        for (let runIdx = 0; runIdx < runConfigs.length; runIdx++) {
            let config = runConfigs[runIdx];
            if (config.month) console.log("%c   ↳ 运行子分支: " + config.label + " (" + config.year + "-" + config.month + ")...", "color: #8e44ad; font-size: 13px;");

            let currentPayloadStr = JSON.stringify(baseDetailPayload);
            if (config.month) currentPayloadStr = currentPayloadStr.replace(/"__MONTH_PLACEHOLDER__"/g, JSON.stringify([config.month]));
            if (config.year) currentPayloadStr = currentPayloadStr.replace(/"__YEAR_PLACEHOLDER__"/g, JSON.stringify([config.year]));

            const detailPayload = JSON.parse(currentPayloadStr);

            let allDataResults = [];
            let globalSumData = null; 
            let currentPage = 1; let limit = 50; let isFetching = true;

            while (isFetching) {


                const response = await fetch("https://netcare.huawei.com/adc-service/web/rest/v1/services////NetCareOperationCenter/cs_nc_operation_center_extend/op_ex_digital_cert_detail_statistics", { headers: fetchHeaders, body: JSON.stringify(detailPayload), method: "POST", credentials: "include" });
                const data = await response.json();
                if (data.status === 9999 || data.errorCode === "9999") throw new Error("请求报错 (9999)：请检查平台登录状态。");

                // 使用全新的兼容提取引擎
                if (!globalSumData) {
                    globalSumData = extractSmartSumData(data);
                }

                let pageItems = extractRows(data);
                if (!pageItems || pageItems.length === 0) break;
                allDataResults = allDataResults.concat(pageItems);

                if (pageItems.length < limit) break;
                currentPage++;
                await new Promise(r => setTimeout(r, 300));
            }

            if (allDataResults.length === 0) {
                console.warn("⚠️ " + config.label + " 未提取到数据，跳过。");
                continue;
            }



            // ==========================================
            // 💾 阶段三：合并与 CSV 动态命名导出
            // ==========================================
            const headers = [];
            allDataResults.forEach(row => { Object.keys(row).forEach(k => { if (!headers.includes(k)) headers.push(k); }); });

            if (globalSumData) {
                let totalRow = {};
                totalRow[headers[0]] = "【总计】"; 
                for (let i = 1; i < headers.length; i++) {
                    let colName = headers[i];
                    totalRow[colName] = getSmartValue(globalSumData[colName]);
                }
                allDataResults.push(totalRow);
            }

            let csvContent = String.fromCharCode(0xFEFF) + headers.join(",") + String.fromCharCode(10); 
            allDataResults.forEach(function(row) {
                let rowArray = [];
                headers.forEach(function(header) {
                    let cellVal = getSmartValue(row[header]);
                    let cellStr = String(cellVal).replace(/"/g, '""');
                    rowArray.push('"' + cellStr + '"');
                });
                csvContent += rowArray.join(",") + String.fromCharCode(10);
            });

            let finalOutputName = "PBI_自动抓取-数字证书_Latest.csv";
            if (config.month) {
                finalOutputName = finalOutputName.replace(".csv", "_" + config.year + "年" + config.month + "月.csv");
            }

            const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
            const link = document.createElement("a");
            link.href = URL.createObjectURL(blob);
            link.download = finalOutputName;

            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);

            let reportLine = config.label + (config.month ? "(" + config.month + "月)" : "") + ": " + (allDataResults.length - (globalSumData ? 1 : 0)) + " 条";
            finalSummary.push(reportLine);
            if (config.month) console.log("%c      ✔️ " + config.label + " ("+ config.year + "-" + config.month +") 数据已触发下载！", "color: #2ecc71;");

            if (runIdx < runConfigs.length - 1) {
                await new Promise(r => setTimeout(r, 1500));
            }
        } // 循环结束

        return "✅ 数据导出成功！子任务: " + finalSummary.join(" | ");
    } catch (error) {
        return "❌ 执行报错: " + error.message;
    }
})();

